async function handlePhotoFiles(e){const existingCount=photos.filter(p=>p.existing).length;const newCount=photos.filter(p=>p.file).length;const files=Array.from(e.target.files||[]).slice(0,Math.max(0,4-newCount));const loaded=await Promise.all(files.map(file=>new Promise(resolve=>{const reader=new FileReader();reader.onload=()=>resolve({file,dataUrl:reader.result,name:file.name});reader.readAsDataURL(file)})));setPhotos(prev=>[...prev,...loaded]);e.target.value=''}
