function canvasPoint(event){const canvas=signatureCanvasRef.current;const rect=canvas.getBoundingClientRect();const t=event.touches&&event.touches[0];const clientX=t?t.clientX:event.clientX;const clientY=t?t.clientY:event.clientY;const scaleX=canvas.width/rect.width;const scaleY=canvas.height/rect.height;return{x:(clientX-rect.left)*scaleX,y:(clientY-rect.top)*scaleY}}
function startSignature(event){event.preventDefault();drawingSignature.current=true;const canvas=signatureCanvasRef.current,ctx=canvas.getContext('2d'),p=canvasPoint(event);ctx.beginPath();ctx.moveTo(p.x,p.y)}
