function clearSignature(){const canvas=signatureCanvasRef.current;if(canvas){canvas.getContext('2d').clearRect(0,0,canvas.width,canvas.height)}setSignatureData('')}
function dataUrlToBlob(dataUrl){const parts=dataUrl.split(','),mime=parts[0].match(/:(.*?);/)[1],bin=atob(parts[1]);let n=bin.length;const arr=new Uint8Array(n);while(n--)arr[n]=bin.charCodeAt(n);return new Blob([arr],{type:mime})}
function pintarFirmaExistente(url){setTimeout(()=>{const canvas=signatureCanvasRef.current;if(!canvas||!url)return;const ctx=canvas.getContext('2d');const img=new Image();img.crossOrigin='anonymous';img.onload=()=>{ctx.clearRect(0,0,canvas.width,canvas.height);ctx.drawImage(img,0,0,canvas.width,canvas.height)};img.src=url},100)}
