function abrirWhatsAppBusiness(tel,mensaje){
  const phone=normalizePhone(tel||'');
  if(!phone) return false;
  const key=phone+'|'+String(mensaje||'');
  const now=Date.now();
  if(whatsappOpenRef.current.key===key && now-whatsappOpenRef.current.time<12000){
    return true;
  }
  whatsappOpenRef.current={key,time:now};
  const text=encodeURIComponent(mensaje||'');
  const isMobile=/iphone|ipad|ipod|android/i.test(navigator.userAgent||'');
  const url=isMobile
    ? `https://wa.me/${phone}?text=${text}`
    : `https://web.whatsapp.com/send?phone=${phone}&text=${text}`;
  const opened=window.open(url,'theclinic_whatsapp_cliente','noopener,noreferrer');
  return !!opened;
}
async function enviarCorreoRecepcion(data,documentUrl){
  const message='Correo automático pendiente de reactivar en módulo separado. Esta versión limpia no incluye backend /api para evitar errores de Vercel.';
  setEmailStatus({status:'error',folio:data.folio,to:data.correo,finishedAt:new Date().toLocaleString('es-MX'),message});
  throw new Error(message);
}
async function enviarWhatsappPdf(dataOverride=null){let data=dataOverride||lastSaved;if(!data&&!dataOverride)data=await guardarRecepcion({preserveForm:true});if(!data)return false;const tel=normalizePhone(data.telefono||'');if(!tel)return false;setLastSaved(data);const documentUrl=documentoRecepcionUrl(data);return abrirWhatsAppBusiness(tel,mensajeRecepcion(data,documentUrl))}
async function enviarComunicaciones(){
  if(communicationLock.current)return;
  communicationLock.current=true;
  setCommunicationSending(true);
  try{
    let data=lastSaved;
    if(!data)data=await guardarRecepcion({preserveForm:true});
    if(!data)return;
    setLastSaved(data);
    const hasEmail=!!(data.correo||'').trim();
    const documentUrl=documentoRecepcionUrl(data);
    let mailOk=false;
    if(hasEmail){
      try{
        setMessage('Enviando correo electrónico automático...');
        const mail=await enviarCorreoRecepcion(data,documentUrl);
        mailOk=true;
        setMessage(`Correo enviado${mail?.id?' · ID '+mail.id:''}. WhatsApp listo para enviar manualmente.`);
      }catch(err){
        setMessage('Correo no enviado: '+err.message+'. WhatsApp listo para enviar manualmente.');
      }
    }else{
      setEmailStatus(null);
    }
    abrirWhatsAppBusiness(data.telefono,mensajeRecepcion(data,documentUrl));
    if(!hasEmail)setMessage('WhatsApp listo para enviar manualmente.');
  }finally{
    communicationLock.current=false;
    setCommunicationSending(false);
  }
}
